	const MANGADEX_DOMAIN = "https://mangadex.org";
	const MANGADEX_API = "https://api.mangadex.org";
	const COVER_BASE_URL = "https://uploads.mangadex.org/covers";
	const SEASONAL_LIST = "77430796-6625-4684-b673-ffae5140f337";
	/**
	* Validates manga ID format, throws error for legacy IDs
	*/
	function checkId(id) {
		if (!id.includes("-")) throw new Error("OLD ID: PLEASE REFRESH AND CLEAR ORPHANED CHAPTERS");
	}
	/**
	* Fetches and parses JSON response from API
	*/
	async function fetchJSON(request) {
		const [response, buffer] = await Application.scheduleRequest(request);
		const data = Application.arrayBufferToUTF8String(buffer);
		const json = typeof data === "string" ? JSON.parse(data) : data;
		if (response.status !== 200) console.log(`Failed to fetch json results for ${request.url}`);
		return json;
	}

